  {
    "type": "std",
    "number": 100,
    "contents": [
      {
        "number": 9776,
        "title": "Internet Group Management Protocol, Version 3",
        "published": "2025-03-28",
        "pages": 48,
        "status": {
          "slug": "standard",
          "name": "Internet Standard"
        },
        "authors": [
          {
            "person": 100664,
            "name": "Brian Haberman",
            "titlepage_name": "",
            "email": "brian@innovationslab.net",
            "affiliation": "Johns Hopkins University Applied Physics Lab",
            "country": ""
          }
        ],
        "group": {
          "acronym": "pim",
          "name": "Protocols for IP Multicast"
        },
        "area": {
          "acronym": "rtg",
          "name": "Routing Area"
        },
        "stream": {
          "slug": "IETF",
          "name": "IETF",
          "description": "Internet Engineering Task Force (IETF)"
        },
        "identifiers": [
          {
            "type": "doi",
            "value": "10.17487/RFC9776"
          }
        ],
        "obsoleted_by": [],
        "updated_by": [],
        "formats": [],
        "abstract": "The Internet Group Management Protocol (IGMP) is the protocol used by IPv4 systems to report their IP multicast group memberships to neighboring multicast routers. Version 3 of IGMP (IGMPv3) adds support for source filtering, that is, the ability for a system to report interest in receiving packets only from specific source addresses, or from all but specific source addresses, sent to a particular multicast address. That information may be used by multicast routing protocols to avoid delivering multicast packets from specific sources to networks where there are no interested receivers.\n\n This document specifies IGMPv3. It is a revised version of RFC 3376 that includes clarifications and fixes for errata, and it is backward compatible with RFC 3376.\n\n This document updates RFC 2236 and obsoletes RFC 3376.",
        "text": "",
        "subseries": [
          {
            "type": "std",
            "number": 100
          }
        ]
      }
    ]
  },
  {
    "type": "std",
    "number": 101,
    "contents": [
      {
        "number": 9777,
        "title": "Multicast Listener Discovery Version 2 (MLDv2) for IPv6",
        "published": "2025-03-28",
        "pages": 56,
        "status": {
          "slug": "standard",
          "name": "Internet Standard"
        },
        "authors": [
          {
            "person": 100664,
            "name": "Brian Haberman",
            "titlepage_name": "",
            "email": "brian@innovationslab.net",
            "affiliation": "Johns Hopkins University Applied Physics Lab",
            "country": ""
          }
        ],
        "group": {
          "acronym": "pim",
          "name": "Protocols for IP Multicast"
        },
        "area": {
          "acronym": "rtg",
          "name": "Routing Area"
        },
        "stream": {
          "slug": "IETF",
          "name": "IETF",
          "description": "Internet Engineering Task Force (IETF)"
        },
        "identifiers": [
          {
            "type": "doi",
            "value": "10.17487/RFC9777"
          }
        ],
        "obsoleted_by": [],
        "updated_by": [],
        "formats": [],
        "abstract": "This document specifies the Multicast Listener Discovery version 2 (MLDv2) protocol. MLD is used by an IPv6 router to discover the presence of multicast listeners on directly attached links and to discover which multicast addresses are of interest to those neighboring nodes. MLDv2 is designed to be interoperable with MLDv1. MLDv2 adds the ability for a node to report interest in listening to packets with a particular multicast address only from specific source addresses or from all sources except for specific source addresses.\n\n This document updates RFC 2710 and obsoletes RFC 3810.",
        "text": "",
        "subseries": [
          {
            "type": "std",
            "number": 101
          }
        ]
      }
    ]
  }
